import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation, useNavigate } from 'react-router-dom';
import { 
  LayoutDashboard, Users, Calendar, CreditCard, Menu, ChevronDown, ChevronRight,
  Package, Receipt, Wallet, UserCircle, BarChart3, ShoppingCart, RefreshCw, 
  Settings as SettingsIcon, LogOut, Landmark, PlusSquare, List,
  Search, Bell, Clock, Shield, Stethoscope, Briefcase
} from 'lucide-react';
import { 
  ViewType, Patient, Appointment, Medicine, Invoice, 
  Expense, Salary, StaffUser, Role, PatientHistory, Prescription, ClinicalService
} from './types';
import DashboardView from './views/DashboardView';
import PatientsView from './views/PatientsView';
import AppointmentsView from './views/AppointmentsView';
import PharmacyView from './views/PharmacyView';
import POSView from './views/POSView';
import BillingView from './views/BillingView';
import ExpensesView from './views/ExpensesView';
import SalariesView from './views/SalariesView';
import UsersView from './views/UsersView';
import ReportsView from './views/ReportsView';
import TreasuryView from './views/TreasuryView';
import SettingsView from './views/SettingsView';
import LoginView from './views/LoginView';
import { daftraApi } from './services/daftraService';
import { supabaseService } from './services/supabaseService';
import { supabase } from './lib/supabase';
import AIAssistantView from './views/AIAssistantView';

export const DhoolLogo = ({ className }: { className?: string }) => (
  <svg viewBox="0 0 100 100" className={className || "w-10 h-10"} fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M50 15C38 15 28 22 25 35C22 55 35 70 45 85C47 88 50 92 50 95C50 92 53 88 55 85C65 70 78 55 75 35C72 22 62 15 50 15Z" stroke="url(#logoGrad)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" />
    <path d="M40 45C45 52 55 52 60 45" stroke="url(#logoGrad)" strokeWidth="4" strokeLinecap="round" opacity="0.6" />
    <defs>
      <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
        <stop offset="0%" stopColor="#0056b3" />
        <stop offset="100%" stopColor="#32cd32" />
      </linearGradient>
    </defs>
  </svg>
);

const AppContent: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<StaffUser | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [expandedGroup, setExpandedGroup] = useState<string | null>(null);
  const [language, setLanguage] = useState<'so' | 'en'>('en');
  const navigate = useNavigate();
  const location = useLocation();

  const [currency, setCurrency] = useState('$');
  const [dateFormat, setDateFormat] = useState('DD/MM/YYYY');
  const [daftraStatus, setDaftraStatus] = useState<'checking' | 'connected' | 'error'>('checking');

  // Real-time Data States
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [clinicalServices, setClinicalServices] = useState<ClinicalService[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('dhool_user');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    const savedLang = localStorage.getItem('dhool_lang');
    if (savedLang) setLanguage(savedLang as any);

    checkDaftra();
  }, []);

  useEffect(() => {
    if (currentUser) {
        loadData();
        setupRealtimeSubscriptions();
    }
  }, [currentUser]);

  const setupRealtimeSubscriptions = () => {
    // Listen for inserts/updates/deletes on key tables
    const channel = supabase.channel('dhool_db_changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'inventory' }, (payload) => {
         // Re-fetch inventory on change
         supabaseService.getInventory().then(data => setInventory(data || []));
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'invoices' }, (payload) => {
         supabaseService.getInvoices().then(data => setInvoices(data || []));
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'patients' }, (payload) => {
         supabaseService.getPatients().then(data => setPatients(data || []));
      })
      .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, (payload) => {
         supabaseService.getAppointments().then(data => setAppointments(data || []));
      })
      .subscribe();

    return () => {
        supabase.removeChannel(channel);
    };
  };

  const checkDaftra = async () => {
    setDaftraStatus('checking');
    try {
      const isConnected = await daftraApi.checkConnection();
      setDaftraStatus(isConnected ? 'connected' : 'error');
    } catch (e) {
      setDaftraStatus('error');
    }
  };

  const loadData = async () => {
    try {
      const [p, m, srv, a, i, e, s, u] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getServices(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices(),
        supabaseService.getExpenses(),
        supabaseService.getSalaries(),
        supabaseService.getUsers()
      ]);
      setPatients(p || []);
      setInventory(m || []);
      setClinicalServices(srv || []);
      setAppointments(a || []);
      setInvoices(i || []);
      setExpenses(e || []);
      setSalaries(s || []);
      setUsers(u || []);
    } catch (error) {
      console.error("Data Load Error:", error);
    }
  };

  const handleLogin = async (email: string, pass: string) => {
    if (email === 'admin@dhool.com' && pass === 'admin123') {
      const fallbackUser: StaffUser = { id: '1', name: 'Super Admin', role: 'Admin', email: 'admin@dhool.com', status: 'Active', avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Admin' };
      setCurrentUser(fallbackUser);
      localStorage.setItem('dhool_user', JSON.stringify(fallbackUser));
      return true;
    }
    const user = await supabaseService.login(email);
    if (user && user.password === pass) {
      setCurrentUser(user);
      localStorage.setItem('dhool_user', JSON.stringify(user));
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('dhool_user');
    navigate('/');
  };

  const handleGroupToggle = (group: string) => {
    if (!isSidebarOpen) {
      setIsSidebarOpen(true);
      setExpandedGroup(group);
    } else {
      setExpandedGroup(expandedGroup === group ? null : group);
    }
  };

  const t = (key: string) => {
    const dict: Record<string, any> = {
      so: {
        dashboard: 'Dashboard-ka',
        pos_grp: 'POS & Iibka',
        services: 'Adeegyada (Services)',
        pos_start: 'Iibka Farmashiga',
        pharmacy: 'Bakhaarka (Pharmacy)',
        sales_grp: 'Maamulka Iibka',
        invoices: 'Biilasha Dhameystiran',
        clients_grp: 'Bukaanada & Macmiisha',
        patients: 'Diiwaanka Bukaanada',
        finance_grp: 'Maaliyadda',
        expenses: 'Kharashyada',
        payroll: 'Mushaharka',
        treasury: 'Qasnadda (Treasury)',
        reports: 'Warbixinnada',
        settings: 'Settings',
        admin: 'User-ada',
        inventory: 'Pharmacy',
        appointments: 'Ballamaha',
        logout: 'Ka Bax',
        pos_sale_success: 'Iibka waa lagu guuleystay',
        userAdded: 'User-ka waa la kaydiyay!',
        errorAddingUser: 'Cillad ayaa dhacday markii la kaydinayay user-ka.'
      },
      en: {
        dashboard: 'Dashboard',
        pos_grp: 'POS & Sales',
        services: 'Clinical Services',
        pos_start: 'Pharmacy POS',
        pharmacy: 'Pharmacy Stock',
        sales_grp: 'Sales Management',
        invoices: 'Invoices',
        clients_grp: 'Clients',
        patients: 'Patients',
        finance_grp: 'Finance',
        expenses: 'Expenses',
        payroll: 'Payroll',
        treasury: 'Treasury & Accounts',
        reports: 'Reports',
        settings: 'Settings',
        admin: 'Users',
        inventory: 'Pharmacy',
        appointments: 'Appointments',
        logout: 'Logout',
        pos_sale_success: 'Sale Successful',
        userAdded: 'User saved successfully!',
        errorAddingUser: 'Error saving user.'
      }
    };
    return dict[language]?.[key] || key;
  };

  const canAccess = (view: ViewType) => {
    if (!currentUser) return false;
    if (currentUser.role === 'Admin') return true;
    switch(view) {
      case 'dashboard': return true;
      case 'patients': case 'appointments': case 'services': return (['Doctor', 'Staff', 'Admin'] as string[]).includes(currentUser.role);
      case 'pos': case 'pharmacy': return (['Staff', 'Admin'] as string[]).includes(currentUser.role);
      case 'invoices': case 'expenses': case 'salaries': case 'reports': case 'treasury': return (['Accountant', 'Admin'] as string[]).includes(currentUser.role);
      case 'users': return false; // Admin check is done above
      default: return true;
    }
  };

  if (!currentUser) return <LoginView onLogin={handleLogin} />;

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900">
      <aside className={`bg-[#111827] text-white transition-all duration-300 ${isSidebarOpen ? 'w-64' : 'w-20'} flex flex-col border-r border-white/5 overflow-y-auto no-scrollbar shadow-2xl flex-shrink-0`}>
        <div className="p-6 mb-4">
          <div className="flex items-center gap-3">
            <div className="bg-white p-1 rounded-xl shadow-lg shrink-0"><DhoolLogo className="w-8 h-8" /></div>
            {isSidebarOpen && <span className="text-xl font-black text-blue-500 tracking-tighter uppercase animate-in fade-in">DHOOL</span>}
          </div>
        </div>

        <nav className="flex-1 px-3">
          <NavItem 
            to="/" 
            label={t('dashboard')} 
            active={location.pathname === '/'} 
            icon={LayoutDashboard} 
            isSidebarOpen={isSidebarOpen}
          />

          <div className="h-4"></div>

          {canAccess('pos') && (
            <NavGroup id="pos" label={t('pos_grp')} isOpen={expandedGroup === 'pos'} onToggle={() => handleGroupToggle('pos')} isSidebarOpen={isSidebarOpen} icon={ShoppingCart}>
               <SubNavItem to="/pos" label={t('pos_start')} active={location.pathname === '/pos'} />
               <SubNavItem to="/pharmacy" label={t('pharmacy')} active={location.pathname === '/pharmacy'} />
            </NavGroup>
          )}

          {canAccess('services') && (
            <NavItem 
              to="/services" 
              label={t('services')} 
              active={location.pathname === '/services'} 
              icon={Stethoscope} 
              isSidebarOpen={isSidebarOpen}
            />
          )}

          {canAccess('invoices') && (
            <NavGroup id="sales" label={t('sales_grp')} isOpen={expandedGroup === 'sales'} onToggle={() => handleGroupToggle('sales')} isSidebarOpen={isSidebarOpen} icon={Receipt}>
              <SubNavItem to="/invoices" label={t('invoices')} active={location.pathname === '/invoices'} />
            </NavGroup>
          )}

          {canAccess('patients') && (
            <NavGroup id="clients" label={t('clients_grp')} isOpen={expandedGroup === 'clients'} onToggle={() => handleGroupToggle('clients')} isSidebarOpen={isSidebarOpen} icon={Users}>
              <SubNavItem to="/patients" label={t('patients')} active={location.pathname === '/patients'} />
            </NavGroup>
          )}

          {canAccess('expenses') && (
            <NavGroup id="finance" label={t('finance_grp')} isOpen={expandedGroup === 'finance'} onToggle={() => handleGroupToggle('finance')} isSidebarOpen={isSidebarOpen} icon={Wallet}>
              <SubNavItem to="/treasury" label={t('treasury')} active={location.pathname === '/treasury'} />
              <SubNavItem to="/expenses" label={t('expenses')} active={location.pathname === '/expenses'} />
              <SubNavItem to="/salaries" label={t('payroll')} active={location.pathname === '/salaries'} />
            </NavGroup>
          )}

          <div className="mt-8 border-t border-white/5 pt-4">
            {canAccess('appointments') && <NavItem to="/appointments" label={t('appointments')} active={location.pathname === '/appointments'} icon={Calendar} isSidebarOpen={isSidebarOpen} />}
            {canAccess('reports') && <NavItem to="/reports" label={t('reports')} active={location.pathname === '/reports'} icon={BarChart3} isSidebarOpen={isSidebarOpen} />}
            <NavItem to="/settings" label={t('settings')} active={location.pathname === '/settings'} icon={SettingsIcon} isSidebarOpen={isSidebarOpen} />
            {canAccess('users') && <NavItem to="/users" label={t('admin')} active={location.pathname === '/users'} icon={Shield} isSidebarOpen={isSidebarOpen} />}
          </div>
        </nav>

        <div className="p-4 mt-auto border-t border-white/5">
          <button onClick={handleLogout} className="w-full flex items-center justify-center px-4 py-2 text-sm font-medium text-rose-400 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
            <LogOut className="w-5 h-5 shrink-0" /> 
            {isSidebarOpen && <span className="ml-2 animate-in fade-in">{t('logout')}</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 z-10 shadow-sm shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400"><Menu className="w-5 h-5" /></button>
          </div>
          <div className="flex items-center gap-6">
            <div className="text-right hidden sm:block">
              <p className="text-xs font-black text-slate-900">{currentUser.name}</p>
              <p className="text-[10px] text-blue-500 font-bold uppercase tracking-widest">{currentUser.role}</p>
            </div>
            <img src={currentUser.avatar} className="w-10 h-10 rounded-2xl border border-slate-200 p-1 bg-slate-50" />
          </div>
        </header>

        <section className="flex-1 overflow-y-auto p-8 bg-[#f8fafc]">
          <Routes>
             <Route path="/" element={<DashboardView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} />} />

             <Route path="/pos" element={<POSView 
                mode="pos" 
                products={inventory} 
                services={[]} 
                currency={currency} 
                processSale={async (items, total, method, disc, isRefund) => {
                  const transactionId = `INV-${Date.now().toString().slice(-6)}`;
                  const finalAmount = isRefund ? -Math.abs(total) : total;
                  const inv: Invoice = { 
                    id: transactionId, 
                    patientName: 'Pharmacy Client', 
                    date: new Date().toISOString().split('T')[0], 
                    amount: finalAmount, 
                    discount: disc, 
                    totalPaid: finalAmount, 
                    status: isRefund ? 'Refunded' : 'Paid', 
                    type: 'Pharmacy', 
                    method: method,
                    isRefund: isRefund 
                  };

                  // Prepare items with current stock for deduction
                  const itemsWithStock = items.map(cartItem => {
                      const found = inventory.find(i => i.id === cartItem.id);
                      return { ...cartItem, currentStock: found ? found.stock : 0 };
                  });

                  return await supabaseService.createTransaction(inv, isRefund ? [] : itemsWithStock); // Only deduct if not refund
                }} 
                t={t} 
                onAddService={async ()=>{}} 
             />} />

             <Route path="/services" element={<POSView 
                mode="services" 
                products={[]} 
                services={clinicalServices}
                currency={currency} 
                processSale={async (items, total, method, disc, isRefund) => {
                  const transactionId = `SRV-${Date.now().toString().slice(-6)}`;
                  const finalAmount = isRefund ? -Math.abs(total) : total;
                  const inv: Invoice = { 
                    id: transactionId, 
                    patientName: 'Clinical Patient', 
                    date: new Date().toISOString().split('T')[0], 
                    amount: finalAmount, 
                    discount: disc, 
                    totalPaid: finalAmount, 
                    status: isRefund ? 'Refunded' : 'Paid', 
                    type: 'Dental', 
                    method: method,
                    isRefund: isRefund
                  };
                  return await supabaseService.createTransaction(inv, []);
                }} 
                onAddService={async (srv) => {
                  await supabaseService.insertService(srv);
                  loadData();
                }}
                t={t} 
             />} />

             <Route path="/patients" element={<PatientsView 
                patients={patients} 
                inventory={inventory}
                addPatient={async p => { 
                   await supabaseService.insertPatient(p); 
                }} 
                patientHistory={[]} 
                addPatientHistory={async h => { await supabaseService.insertHistory(h); }} 
                prescriptions={[]} 
                addPrescription={async pr => {}} 
                user={currentUser} 
                t={t} 
             />} />

             <Route path="/appointments" element={<AppointmentsView appointments={appointments} patients={patients} setAppointments={setAppointments} onAddAppointment={async a => { await supabaseService.insertAppointment(a); loadData(); }} />} />

             <Route path="/pharmacy" element={<PharmacyView 
                inventory={inventory} 
                setInventory={setInventory} 
                onAddMedicine={async m => { await supabaseService.insertMedicine(m); }} 
                onUpdateMedicine={async (id, u) => { await supabaseService.updateMedicine(id, u); }}
                onDeleteMedicine={async id => { await supabaseService.deleteMedicine(id); }}
             />} />

             <Route path="/invoices" element={<BillingView invoices={invoices} />} />

             <Route path="/expenses" element={<ExpensesView expenses={expenses} setExpenses={setExpenses} onAdd={async e => { await supabaseService.insertExpense(e); }} />} />

             <Route path="/salaries" element={<SalariesView salaries={salaries} setSalaries={setSalaries} />} />

             <Route path="/treasury" element={<TreasuryView invoices={invoices} expenses={expenses} salaries={salaries} />} />

             <Route path="/reports" element={<ReportsView patients={patients} appointments={appointments} inventory={inventory} invoices={invoices} expenses={expenses} salaries={salaries} />} />

             <Route path="/users" element={<UsersView appUsers={users} addUser={async u => { 
                  try { 
                    const n = await supabaseService.insertUser(u); 
                    loadData(); 
                    return {success: !!n}; 
                  } catch (e) { 
                    return {success: false, error: 'Database Error'}; 
                  } 
             }} deleteUser={async id => { await supabaseService.deleteUser(id); loadData(); }} t={t} currentUser={currentUser} />} />

             <Route path="/settings" element={<SettingsView 
                  user={currentUser} 
                  language={language} 
                  setLanguage={(l) => { setLanguage(l); localStorage.setItem('dhool_lang', l); }} 
                  currency={currency} 
                  setCurrency={setCurrency} 
                  dateFormat={dateFormat} 
                  setDateFormat={setDateFormat} 
                  t={t} 
                  updateCurrentUser={async (name, pass) => {
                    const updated = await supabaseService.updateUser(currentUser.id, { name, ...(pass ? {password: pass} : {}) });
                    if (updated) { setCurrentUser(updated); localStorage.setItem('dhool_user', JSON.stringify(updated)); return { success: true }; }
                    return { success: false, error: 'Update Failed' };
                  }}
                  daftraStatus={daftraStatus}
                  checkDaftraConnection={checkDaftra}
             />} />
          </Routes>
        </section>

        {/* Global AI Chatbot Button */}
        <div className="fixed bottom-8 right-8 z-50">
          <button 
             onClick={() => window.open('/ai-assistant', 'AIAssistant', 'width=400,height=600')}
             className="w-14 h-14 bg-blue-600 rounded-full flex items-center justify-center text-white shadow-2xl hover:scale-110 transition-transform cursor-pointer"
             title="AI Clinical Assistant"
          >
             <Briefcase className="w-6 h-6" />
          </button>
        </div>
      </main>
    </div>
  );
};

const App: React.FC = () => (
  <Router>
    <Routes>
      <Route path="/ai-assistant" element={<AIAssistantView />} />
      <Route path="/*" element={<AppContent />} />
    </Routes>
  </Router>
);

// Sidebar components with unified typography using React Router Link
const NavItem = ({ to, label, icon: Icon, active, isSidebarOpen }: any) => (
  <Link 
    to={to} 
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
      active ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/30' : 'text-slate-400 hover:text-white hover:bg-white/5'
    }`}
    title={!isSidebarOpen ? label : ''}
  >
    <Icon className="w-5 h-5 shrink-0" /> 
    {isSidebarOpen && <span className="text-sm font-bold tracking-tight animate-in fade-in">{label}</span>}
  </Link>
);

const NavGroup = ({ label, icon: Icon, isOpen, onToggle, isSidebarOpen, children }: any) => (
  <div className="mb-1">
    <button 
      onClick={onToggle} 
      className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all ${
        isOpen ? 'bg-white/5 text-blue-400' : 'text-slate-400 hover:text-white'
      }`}
      title={!isSidebarOpen ? label : ''}
    >
      <div className="flex items-center gap-3">
        <Icon className="w-5 h-5 shrink-0" />
        {isSidebarOpen && <span className="text-sm font-bold tracking-tight animate-in fade-in">{label}</span>}
      </div>
      {isSidebarOpen && (isOpen ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />)}
    </button>
    {isOpen && isSidebarOpen && (
      <div className="mt-1 ml-4 border-l border-white/5 pl-2 space-y-1 animate-in slide-in-from-top-2">
        {children}
      </div>
    )}
  </div>
);

const SubNavItem = ({ to, label, active }: any) => (
  <Link 
    to={to} 
    className={`block w-full text-left px-4 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
      active ? 'text-blue-500 bg-blue-500/10' : 'text-slate-500 hover:text-white hover:bg-white/5'
    }`}
  >
    {label}
  </Link>
);

export default App;

-- Supabase SQL Schema for Dhool Dental Clinic
-- Run this in the SQL Editor of your Supabase Dashboard

-- 1. Create Users Table
CREATE TABLE IF NOT EXISTS users (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  role TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL,
  status TEXT DEFAULT 'Active',
  avatar TEXT,
  password TEXT
);

-- 2. Create Patients Table
-- Columns quoted to match camelCase types in frontend
CREATE TABLE IF NOT EXISTS patients (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  age INTEGER,
  phone TEXT,
  email TEXT,
  "lastVisit" TEXT,
  "medicalHistory" JSONB DEFAULT '[]'::jsonb,
  condition TEXT,
  balance NUMERIC DEFAULT 0
);

-- 3. Create Inventory Table
CREATE TABLE IF NOT EXISTS inventory (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  stock INTEGER DEFAULT 0,
  price NUMERIC DEFAULT 0,
  "expiryDate" TEXT,
  category TEXT,
  image TEXT
);

-- 4. Create Services Table
CREATE TABLE IF NOT EXISTS services (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  price NUMERIC DEFAULT 0,
  category TEXT
);

-- 5. Create Appointments Table
CREATE TABLE IF NOT EXISTS appointments (
  id TEXT PRIMARY KEY,
  "patientId" TEXT REFERENCES patients(id),
  "patientName" TEXT,
  doctor TEXT,
  date TEXT,
  time TEXT,
  status TEXT,
  reason TEXT
);

-- 6. Create Invoices Table
CREATE TABLE IF NOT EXISTS invoices (
  id TEXT PRIMARY KEY,
  "patientName" TEXT,
  date TEXT,
  amount NUMERIC,
  discount NUMERIC DEFAULT 0,
  "totalPaid" NUMERIC,
  status TEXT,
  type TEXT,
  method TEXT,
  "isRefund" BOOLEAN DEFAULT FALSE
);

-- 7. Create Expenses Table
CREATE TABLE IF NOT EXISTS expenses (
  id TEXT PRIMARY KEY,
  description TEXT,
  category TEXT,
  amount NUMERIC,
  date TEXT
);

-- 8. Create Salaries Table
CREATE TABLE IF NOT EXISTS salaries (
  id TEXT PRIMARY KEY,
  "staffName" TEXT,
  role TEXT,
  amount NUMERIC,
  month TEXT,
  date TEXT
);

-- 9. Create Patient History Table
CREATE TABLE IF NOT EXISTS patient_history (
  id TEXT PRIMARY KEY,
  "patientId" TEXT REFERENCES patients(id),
  date TEXT,
  diagnosis TEXT,
  treatment TEXT,
  notes TEXT,
  "doctorName" TEXT
);

-- 10. Enable Row Level Security (Recommended)
ALTER TABLE users ENABLE ROW LEVEL SECURITY;
