import { useData } from '../context/DataContext';

const ReportsView: React.FC = () => {
  const { patients, appointments, inventory, invoices, expenses, salaries } = useData();
  const [reportType, setReportType] = useState<'financial' | 'inventory' | 'clinical'>('financial');

  // Date Filtering State
  const [startDate, setStartDate] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]); // First day of current month
  const [endDate, setEndDate] = useState(new Date().toISOString().split('T')[0]); // Today

  // Filter Helper
  const isWithinRange = (dateString: string) => {
    return dateString >= startDate && dateString <= endDate;
  };

  // Filtered Data
  const filteredInvoices = invoices.filter(i => isWithinRange(i.date));
  const filteredExpenses = expenses.filter(e => isWithinRange(e.date));
  const filteredSalaries = salaries.filter(s => isWithinRange(s.date));
  const filteredAppointments = appointments.filter(a => isWithinRange(a.date));

  // Calculations based on filtered data
  const revenue = filteredInvoices.filter(inv => inv.status === 'Paid').reduce((acc, i) => acc + i.amount, 0);
  const refunds = filteredInvoices.filter(inv => inv.status === 'Refunded').reduce((acc, i) => acc + Math.abs(i.amount), 0);
  const netRevenue = revenue - refunds; // Actual money kept

  const expenseTotal = filteredExpenses.reduce((acc, i) => acc + i.amount, 0);
  const salaryTotal = filteredSalaries.reduce((acc, i) => acc + i.amount, 0);
  const totalOutflow = expenseTotal + salaryTotal;

  const netProfit = netRevenue - totalOutflow;

  // Breakdown by Type
  const pharmacyRevenue = filteredInvoices.filter(i => i.type === 'Pharmacy' && i.status === 'Paid').reduce((acc, i) => acc + i.amount, 0);
  const clinicalRevenue = filteredInvoices.filter(i => i.type === 'Dental' && i.status === 'Paid').reduce((acc, i) => acc + i.amount, 0);

  const financialData = [
    { name: 'Pharmacy Sales', value: pharmacyRevenue, fill: '#3b82f6' },
    { name: 'Clinical Revenue', value: clinicalRevenue, fill: '#8b5cf6' },
    { name: 'Operational Exp', value: expenseTotal, fill: '#f43f5e' },
    { name: 'Staff Salaries', value: salaryTotal, fill: '#fb923c' },
  ];

  return (
