import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabaseService } from '../services/supabaseService';
import { daftraApi } from '../services/daftraService';
import { supabase } from '../lib/supabase';
import { 
  Patient, Medicine, Appointment, Invoice, Expense, Salary, 
  StaffUser, ClinicalService, PatientHistory, Prescription 
} from '../types';

interface DataContextType {
  patients: Patient[];
  inventory: Medicine[];
  clinicalServices: ClinicalService[];
  appointments: Appointment[];
  invoices: Invoice[];
  expenses: Expense[];
  salaries: Salary[];
  users: StaffUser[];
  daftraStatus: 'checking' | 'connected' | 'error';
  refreshData: () => Promise<void>;
  checkDaftra: () => Promise<void>;

  // Actions
  addNewPatient: (p: Patient) => Promise<void>;
  addNewHistory: (h: PatientHistory) => Promise<void>;
  addNewAppointment: (a: Appointment) => Promise<void>;
  addNewMedicine: (m: Medicine) => Promise<void>;
  updateMed: (id: string, m: Partial<Medicine>) => Promise<void>;
  deleteMed: (id: string) => Promise<void>;
  addService: (s: ClinicalService) => Promise<void>;
  addTransaction: (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => Promise<boolean>;
  addExpense: (e: Expense) => Promise<void>;
  addSalary: (s: Salary) => Promise<void>;
  addNewUser: (u: StaffUser) => Promise<{success: boolean, error?: string}>;
  removeUser: (id: string) => Promise<void>;
  updateUserProfile: (id: string, data: Partial<StaffUser>) => Promise<StaffUser | null>;

  // Loading states
  isLoading: boolean;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [clinicalServices, setClinicalServices] = useState<ClinicalService[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);
  const [daftraStatus, setDaftraStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isLoading, setIsLoading] = useState(true);

  const refreshData = async () => {
    try {
      // Execute in parallel but handle failures gracefully for each
      const p = await supabaseService.getPatients();
      if(p) setPatients(p);

      const m = await supabaseService.getInventory();
      if(m) setInventory(m);

      const srv = await supabaseService.getServices();
      if(srv) setClinicalServices(srv);

      const a = await supabaseService.getAppointments();
      if(a) setAppointments(a);

      const i = await supabaseService.getInvoices();
      if(i) setInvoices(i);

      const e = await supabaseService.getExpenses();
      if(e) setExpenses(e);

      const s = await supabaseService.getSalaries();
      if(s) setSalaries(s);

      const u = await supabaseService.getUsers();
      if(u) setUsers(u);

    } catch (error) {
      console.error("Data Load Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const checkDaftra = async () => {
    setDaftraStatus('checking');
    try {
      const isConnected = await daftraApi.checkConnection();
      setDaftraStatus(isConnected ? 'connected' : 'error');
    } catch (e) {
      setDaftraStatus('error');
    }
  };

  useEffect(() => {
    refreshData();
    checkDaftra();

    // Real-time Subscriptions - wrapped in try/catch to prevent crash if network fails
    try {
      const channel = supabase.channel('dhool_global_changes')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'inventory' }, () => {
           supabaseService.getInventory().then(data => data && setInventory(data));
        })
        .on('postgres_changes', { event: '*', schema: 'public', table: 'invoices' }, () => {
           supabaseService.getInvoices().then(data => data && setInvoices(data));
        })
        .on('postgres_changes', { event: '*', schema: 'public', table: 'patients' }, () => {
           supabaseService.getPatients().then(data => data && setPatients(data));
        })
        .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' }, () => {
           supabaseService.getAppointments().then(data => data && setAppointments(data));
        })
        .subscribe();

      return () => {
          supabase.removeChannel(channel);
      };
    } catch (e) {
      console.warn("Realtime subscription failed", e);
    }
  }, []);

  // --- Wrapper Functions that Update State Immediately ---

  const addNewPatient = async (p: Patient) => {
    await supabaseService.insertPatient(p);
    setPatients(prev => [...prev, p]);
  };

  const addNewHistory = async (h: PatientHistory) => {
    await supabaseService.insertHistory(h);
    // History is usually nested or fetched on demand, but we can refresh if needed
  };

  const addNewAppointment = async (a: Appointment) => {
    await supabaseService.insertAppointment(a);
    setAppointments(prev => [a, ...prev]);
  };

  const addNewMedicine = async (m: Medicine) => {
    await supabaseService.insertMedicine(m);
    setInventory(prev => [...prev, m]);
  };

  const updateMed = async (id: string, m: Partial<Medicine>) => {
    await supabaseService.updateMedicine(id, m);
    setInventory(prev => prev.map(item => item.id === id ? { ...item, ...m } : item));
  };

  const deleteMed = async (id: string) => {
    await supabaseService.deleteMedicine(id);
    setInventory(prev => prev.filter(item => item.id !== id));
  };

  const addService = async (s: ClinicalService) => {
    await supabaseService.insertService(s);
    setClinicalServices(prev => [...prev, s]);
  };

  const addTransaction = async (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => {
    const success = await supabaseService.createTransaction(inv, items);
    if (success) {
        setInvoices(prev => [inv, ...prev]);
        // Update inventory locally if items were deducted
        if (items) {
            const itemMap = new Map(items.map(i => [i.id, i.quantity]));
            setInventory(prev => prev.map(prod => {
                const qty = itemMap.get(prod.id);
                if (qty) return { ...prod, stock: Math.max(0, prod.stock - qty) };
                return prod;
            }));
        }
    }
    return success;
  };

  const addExpense = async (e: Expense) => {
    await supabaseService.insertExpense(e);
    setExpenses(prev => [...prev, e]);
  };

  const addSalary = async (s: Salary) => {
    await supabaseService.insertSalary(s);
    setSalaries(prev => [...prev, s]);
  };

  const addNewUser = async (u: StaffUser) => {
    try {
        const res = await supabaseService.insertUser(u);
        setUsers(prev => [...prev, u]);
        return { success: !!res };
    } catch(e) {
        return { success: false, error: 'Database Error' };
    }
  };

  const removeUser = async (id: string) => {
    await supabaseService.deleteUser(id);
    setUsers(prev => prev.filter(u => u.id !== id));
  };

  const updateUserProfile = async (id: string, data: Partial<StaffUser>) => {
     const updated = await supabaseService.updateUser(id, data);
     if (updated) {
        setUsers(prev => prev.map(u => u.id === id ? updated : u));
     }
     return updated;
  };

  return (
    <DataContext.Provider value={{
      patients, inventory, clinicalServices, appointments, invoices, expenses, salaries, users, daftraStatus,
      refreshData, checkDaftra,
      addNewPatient, addNewHistory, addNewAppointment, addNewMedicine, updateMed, deleteMed, addService,
      addTransaction, addExpense, addSalary, addNewUser, removeUser, updateUserProfile,
      isLoading
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

