import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabaseService } from '../services/supabaseService';
import { daftraApi } from '../services/daftraService';
import { supabase } from '../lib/supabase';
import { 
  Patient, Medicine, Appointment, Invoice, Expense, Salary, 
  StaffUser, ClinicalService, PatientHistory, Prescription 
} from '../types';

interface DataContextType {
  patients: Patient[];
  inventory: Medicine[];
  clinicalServices: ClinicalService[];
  appointments: Appointment[];
  invoices: Invoice[];
  expenses: Expense[];
  salaries: Salary[];
  users: StaffUser[];
  patientHistory: PatientHistory[];
  daftraStatus: 'checking' | 'connected' | 'error';
  refreshData: () => Promise<void>;
  checkDaftra: () => Promise<void>;

  // Actions
  addNewPatient: (p: Patient) => Promise<void>;
  addNewHistory: (h: PatientHistory) => Promise<void>;
  addNewAppointment: (a: Appointment) => Promise<void>;
  addNewMedicine: (m: Medicine) => Promise<void>;
  updateMed: (id: string, m: Partial<Medicine>) => Promise<void>;
  deleteMed: (id: string) => Promise<void>;
  addService: (s: ClinicalService) => Promise<void>;
  addTransaction: (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => Promise<boolean>;
  addExpense: (e: Expense) => Promise<void>;
  addSalary: (s: Salary) => Promise<void>;
  addNewUser: (u: StaffUser) => Promise<{success: boolean, error?: string}>;
  removeUser: (id: string) => Promise<void>;
  updateUserProfile: (id: string, data: Partial<StaffUser>) => Promise<StaffUser | null>;

  // Loading states
  isLoading: boolean;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [clinicalServices, setClinicalServices] = useState<ClinicalService[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [daftraStatus, setDaftraStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isLoading, setIsLoading] = useState(true);

  const refreshData = async () => {
    try {
      const p = await supabaseService.getPatients();
      if(p) setPatients(p);

      const m = await supabaseService.getInventory();
      if(m) setInventory(m);

      const srv = await supabaseService.getServices();
      if(srv) setClinicalServices(srv);

      const a = await supabaseService.getAppointments();
      if(a) setAppointments(a);

      const i = await supabaseService.getInvoices();
      if(i) setInvoices(i);

      const e = await supabaseService.getExpenses();
      if(e) setExpenses(e);

      const s = await supabaseService.getSalaries();
      if(s) setSalaries(s);

      const u = await supabaseService.getUsers();
      if(u) setUsers(u);

      // We should ideally have a method to get all history or patient specific
      // For this demo, we assume history is fetched or we can implement getHistory
      // Let's check local storage for history since supabaseService uses it
      const h = JSON.parse(localStorage.getItem('dhool_local_history') || '[]');
      setPatientHistory(h);

    } catch (error) {
      console.error("Data Load Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  const checkDaftra = async () => {
    setDaftraStatus('checking');
    try {
      const isConnected = await daftraApi.checkConnection();
      setDaftraStatus(isConnected ? 'connected' : 'error');
    } catch (e) {
      setDaftraStatus('error');
    }
  };

  useEffect(() => {
    refreshData();
    checkDaftra();
  }, []);

  const addNewPatient = async (p: Patient) => {
    await supabaseService.insertPatient(p);
    setPatients(prev => [...prev, p]);
  };

  const addNewHistory = async (h: PatientHistory) => {
    await supabaseService.insertHistory(h);
    setPatientHistory(prev => [h, ...prev]);
  };

  const addNewAppointment = async (a: Appointment) => {
    await supabaseService.insertAppointment(a);
    setAppointments(prev => [a, ...prev]);
  };

  const addNewMedicine = async (m: Medicine) => {
    await supabaseService.insertMedicine(m);
    setInventory(prev => [...prev, m]);
  };

  const updateMed = async (id: string, m: Partial<Medicine>) => {
    await supabaseService.updateMedicine(id, m);
    setInventory(prev => prev.map(item => item.id === id ? { ...item, ...m } : item));
  };

  const deleteMed = async (id: string) => {
    await supabaseService.deleteMedicine(id);
    setInventory(prev => prev.filter(item => item.id !== id));
  };

  const addService = async (s: ClinicalService) => {
    await supabaseService.insertService(s);
    setClinicalServices(prev => [...prev, s]);
  };

  const addTransaction = async (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => {
    const success = await supabaseService.createTransaction(inv, items);
    if (success) {
        setInvoices(prev => [inv, ...prev]);
        if (items) {
            const itemMap = new Map(items.map(i => [i.id, i.quantity]));
            setInventory(prev => prev.map(prod => {
                const qty = itemMap.get(prod.id);
                if (qty) return { ...prod, stock: Math.max(0, prod.stock - qty) };
                return prod;
            }));
        }
    }
    return success;
  };

  const addExpense = async (e: Expense) => {
    await supabaseService.insertExpense(e);
    setExpenses(prev => [...prev, e]);
  };

  const addSalary = async (s: Salary) => {
    await supabaseService.insertSalary(s);
    setSalaries(prev => [...prev, s]);
  };

  const addNewUser = async (u: StaffUser) => {
    try {
        const res = await supabaseService.insertUser(u);
        setUsers(prev => [...prev, u]);
        return { success: !!res };
    } catch(e) {
        return { success: false, error: 'Database Error' };
    }
  };

  const removeUser = async (id: string) => {
    await supabaseService.deleteUser(id);
    setUsers(prev => prev.filter(u => u.id !== id));
  };

  const updateUserProfile = async (id: string, data: Partial<StaffUser>) => {
     const updated = await supabaseService.updateUser(id, data);
     if (updated) {
        setUsers(prev => prev.map(u => u.id === id ? updated : u));
     }
     return updated;
  };

  return (
    <DataContext.Provider value={{
      patients, inventory, clinicalServices, appointments, invoices, expenses, salaries, users, patientHistory, daftraStatus,
      refreshData, checkDaftra,
      addNewPatient, addNewHistory, addNewAppointment, addNewMedicine, updateMed, deleteMed, addService,
      addTransaction, addExpense, addSalary, addNewUser, removeUser, updateUserProfile,
      isLoading
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

import { supabase } from '../lib/supabase';
import { Patient, Medicine, Appointment, Invoice, PatientHistory, StaffUser, ClinicalService, Expense, Salary } from '../types';

const KEYS = {
  USERS: 'dhool_local_users',
  PATIENTS: 'dhool_local_patients',
  INVENTORY: 'dhool_local_inventory',
  SERVICES: 'dhool_local_services',
  APPOINTMENTS: 'dhool_local_appointments',
  INVOICES: 'dhool_local_invoices',
  EXPENSES: 'dhool_local_expenses',
  SALARIES: 'dhool_local_salaries',
  HISTORY: 'dhool_local_history'
};

const handleRequest = async <T>(
  supabasePromise: any, 
  localKey: string, 
  fallbackAction: 'get' | 'insert' | 'update' | 'delete',
  payload?: any
): Promise<T | any> => {
  try {
    const response = await Promise.resolve(supabasePromise);
    const { data, error } = response || { data: null, error: new Error("Supabase response null") };
    if (error) throw error;
    if (fallbackAction === 'get' && data) {
       localStorage.setItem(localKey, JSON.stringify(data));
    }
    return data;
  } catch (error) {
    console.warn(`Supabase ${fallbackAction} failed for ${localKey}. Using Local Storage.`, error);
    let localData = JSON.parse(localStorage.getItem(localKey) || '[]');

    if (fallbackAction === 'get') return localData;

    if (fallbackAction === 'insert') {
      const newItem = Array.isArray(payload) ? payload[0] : payload;
      const updatedList = [...localData, newItem];
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return newItem;
    }

    if (fallbackAction === 'update') {
      const updatedList = localData.map((item: any) => item.id === payload.id ? { ...item, ...payload.updates } : item);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return payload.updates;
    }

    if (fallbackAction === 'delete') {
      const updatedList = localData.filter((item: any) => item.id !== payload);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return null;
    }
  }
};

export const supabaseService = {
  // Auth
  login: async (email: string) => {
    try {
      const { data, error } = await supabase.from('users').select('*').eq('email', email).single();
      if (error) throw error;
      return data as StaffUser;
    } catch (e) {
      const localUsers: StaffUser[] = JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
      return localUsers.find(u => u.email === email) || null;
    }
  },

  // Users CRUD
  getUsers: async () => handleRequest(supabase.from('users').select('*').order('name'), KEYS.USERS, 'get'),
  insertUser: async (user: StaffUser) => handleRequest(supabase.from('users').insert([user]).select(), KEYS.USERS, 'insert', user),
  updateUser: async (id: string, updates: Partial<StaffUser>) => handleRequest(supabase.from('users').update(updates).eq('id', id).select(), KEYS.USERS, 'update', { id, updates }),
  deleteUser: async (id: string) => handleRequest(supabase.from('users').delete().eq('id', id), KEYS.USERS, 'delete', id),

  // Patients CRUD
  getPatients: async () => handleRequest(supabase.from('patients').select('*').order('name'), KEYS.PATIENTS, 'get'),
  insertPatient: async (patient: Patient) => handleRequest(supabase.from('patients').insert([patient]).select(), KEYS.PATIENTS, 'insert', patient),
  updatePatient: async (id: string, updates: Partial<Patient>) => handleRequest(supabase.from('patients').update(updates).eq('id', id).select(), KEYS.PATIENTS, 'update', { id, updates }),
  deletePatient: async (id: string) => handleRequest(supabase.from('patients').delete().eq('id', id), KEYS.PATIENTS, 'delete', id),

  // Inventory CRUD
  getInventory: async () => handleRequest(supabase.from('inventory').select('*').order('name'), KEYS.INVENTORY, 'get'),
  insertMedicine: async (medicine: Medicine) => handleRequest(supabase.from('inventory').insert([medicine]).select(), KEYS.INVENTORY, 'insert', medicine),
  updateMedicine: async (id: string, updates: Partial<Medicine>) => handleRequest(supabase.from('inventory').update(updates).eq('id', id).select(), KEYS.INVENTORY, 'update', { id, updates }),
  deleteMedicine: async (id: string) => handleRequest(supabase.from('inventory').delete().eq('id', id), KEYS.INVENTORY, 'delete', id),

  // Services CRUD
  getServices: async () => handleRequest(supabase.from('services').select('*').order('name'), KEYS.SERVICES, 'get'),
  insertService: async (service: ClinicalService) => handleRequest(supabase.from('services').insert([service]).select(), KEYS.SERVICES, 'insert', service),
  deleteService: async (id: string) => handleRequest(supabase.from('services').delete().eq('id', id), KEYS.SERVICES, 'delete', id),

  // Appointments CRUD
  getAppointments: async () => handleRequest(supabase.from('appointments').select('*').order('date'), KEYS.APPOINTMENTS, 'get'),
  insertAppointment: async (appointment: Appointment) => handleRequest(supabase.from('appointments').insert([appointment]).select(), KEYS.APPOINTMENTS, 'insert', appointment),

  // Transactions (Invoices)
  getInvoices: async () => handleRequest(supabase.from('invoices').select('*').order('date', { ascending: false }), KEYS.INVOICES, 'get'),
  createTransaction: async (invoice: Invoice, itemsToDeduct?: { id: string; quantity: number, currentStock: number }[]) => {
    try {
        const { error: invError } = await supabase.from('invoices').insert([invoice]);
        if (invError) throw invError;
        if (itemsToDeduct && itemsToDeduct.length > 0) {
            for (const item of itemsToDeduct) {
                const newStock = Math.max(0, item.currentStock - item.quantity);
                await supabase.from('inventory').update({ stock: newStock }).eq('id', item.id);
            }
        }
        return true;
    } catch (e) {
        console.error("Supabase Trans Error:", e);
        let local = JSON.parse(localStorage.getItem(KEYS.INVOICES) || '[]');
        localStorage.setItem(KEYS.INVOICES, JSON.stringify([invoice, ...local]));
        return true; // Return true as we stored locally
    }
  },

  // Finance CRUD
  getExpenses: async () => handleRequest(supabase.from('expenses').select('*').order('date', { ascending: false }), KEYS.EXPENSES, 'get'),
  insertExpense: async (expense: Expense) => handleRequest(supabase.from('expenses').insert([expense]).select(), KEYS.EXPENSES, 'insert', expense),
  deleteExpense: async (id: string) => handleRequest(supabase.from('expenses').delete().eq('id', id), KEYS.EXPENSES, 'delete', id),

  getSalaries: async () => handleRequest(supabase.from('salaries').select('*').order('date', { ascending: false }), KEYS.SALARIES, 'get'),
  insertSalary: async (salary: Salary) => handleRequest(supabase.from('salaries').insert([salary]).select(), KEYS.SALARIES, 'insert', salary),
  deleteSalary: async (id: string) => handleRequest(supabase.from('salaries').delete().eq('id', id), KEYS.SALARIES, 'delete', id),

  // History CRUD
  insertHistory: async (history: PatientHistory) => handleRequest(supabase.from('patient_history').insert([history]).select(), KEYS.HISTORY, 'insert', history)
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabaseService } from '../services/supabaseService';
import { daftraApi } from '../services/daftraService';
import { 
  Patient, Medicine, Appointment, Invoice, Expense, Salary, 
  StaffUser, ClinicalService, PatientHistory 
} from '../types';

interface DataContextType {
  patients: Patient[];
  inventory: Medicine[];
  clinicalServices: ClinicalService[];
  appointments: Appointment[];
  invoices: Invoice[];
  expenses: Expense[];
  salaries: Salary[];
  users: StaffUser[];
  patientHistory: PatientHistory[];
  daftraStatus: 'checking' | 'connected' | 'error';
  refreshData: () => Promise<void>;

  // Patient Actions
  addNewPatient: (p: Patient) => Promise<void>;
  updatePat: (id: string, p: Partial<Patient>) => Promise<void>;
  deletePat: (id: string) => Promise<void>;

  // History
  addNewHistory: (h: PatientHistory) => Promise<void>;

  // Inventory
  addNewMedicine: (m: Medicine) => Promise<void>;
  updateMed: (id: string, m: Partial<Medicine>) => Promise<void>;
  deleteMed: (id: string) => Promise<void>;

  // Services
  addService: (s: ClinicalService) => Promise<void>;
  removeService: (id: string) => Promise<void>;

  // Sales
  addTransaction: (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => Promise<boolean>;

  // Appointments
  addNewAppointment: (a: Appointment) => Promise<void>;

  // Finance
  addExpense: (e: Expense) => Promise<void>;
  removeExpense: (id: string) => Promise<void>;
  addSalary: (s: Salary) => Promise<void>;
  removeSalary: (id: string) => Promise<void>;

  // User Management
  addNewUser: (u: StaffUser) => Promise<{success: boolean, error?: string}>;
  removeUser: (id: string) => Promise<void>;
  updateUserProfile: (id: string, data: Partial<StaffUser>) => Promise<StaffUser | null>;

  isLoading: boolean;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [clinicalServices, setClinicalServices] = useState<ClinicalService[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [daftraStatus, setDaftraStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isLoading, setIsLoading] = useState(true);

  const refreshData = async () => {
    try {
      const [p, m, srv, a, i, e, s, u] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getServices(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices(),
        supabaseService.getExpenses(),
        supabaseService.getSalaries(),
        supabaseService.getUsers()
      ]);

      if (p) setPatients(p);
      if (m) setInventory(m);
      if (srv) setClinicalServices(srv);
      if (a) setAppointments(a);
      if (i) setInvoices(i);
      if (e) setExpenses(e);
      if (s) setSalaries(s);
      if (u) setUsers(u);

      const h = JSON.parse(localStorage.getItem('dhool_local_history') || '[]');
      setPatientHistory(h);
    } catch (error) {
      console.error("Context Refresh Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
    daftraApi.checkConnection().then(res => setDaftraStatus(res ? 'connected' : 'error'));
  }, []);

  const addNewPatient = async (p: Patient) => {
    await supabaseService.insertPatient(p);
    setPatients(prev => [...prev, p]);
  };
  const updatePat = async (id: string, p: Partial<Patient>) => {
    await supabaseService.updatePatient(id, p);
    setPatients(prev => prev.map(item => item.id === id ? { ...item, ...p } : item));
  };
  const deletePat = async (id: string) => {
    await supabaseService.deletePatient(id);
    setPatients(prev => prev.filter(p => p.id !== id));
  };

  const addNewHistory = async (h: PatientHistory) => {
    await supabaseService.insertHistory(h);
    setPatientHistory(prev => [h, ...prev]);
    localStorage.setItem('dhool_local_history', JSON.stringify([h, ...patientHistory]));
  };

  const addNewMedicine = async (m: Medicine) => {
    await supabaseService.insertMedicine(m);
    setInventory(prev => [...prev, m]);
  };
  const updateMed = async (id: string, m: Partial<Medicine>) => {
    await supabaseService.updateMedicine(id, m);
    setInventory(prev => prev.map(item => item.id === id ? { ...item, ...m } : item));
  };
  const deleteMed = async (id: string) => {
    await supabaseService.deleteMedicine(id);
    setInventory(prev => prev.filter(m => m.id !== id));
  };

  const addService = async (s: ClinicalService) => {
    await supabaseService.insertService(s);
    setClinicalServices(prev => [...prev, s]);
  };
  const removeService = async (id: string) => {
    await supabaseService.deleteService(id);
    setClinicalServices(prev => prev.filter(s => s.id !== id));
  };

  const addTransaction = async (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => {
    const success = await supabaseService.createTransaction(inv, items);
    if (success) {
      setInvoices(prev => [inv, ...prev]);
      if (items) {
        const itemMap = new Map(items.map(i => [i.id, i.quantity]));
        setInventory(prev => prev.map(prod => {
          const qty = itemMap.get(prod.id);
          if (qty) return { ...prod, stock: Math.max(0, prod.stock - qty) };
          return prod;
        }));
      }
    }
    return success;
  };

  const addNewAppointment = async (a: Appointment) => {
    await supabaseService.insertAppointment(a);
    setAppointments(prev => [a, ...prev]);
  };

  const addExpense = async (e: Expense) => {
    await supabaseService.insertExpense(e);
    setExpenses(prev => [e, ...prev]);
  };
  const removeExpense = async (id: string) => {
    await supabaseService.deleteExpense(id);
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const addSalary = async (s: Salary) => {
    await supabaseService.insertSalary(s);
    setSalaries(prev => [s, ...prev]);
  };
  const removeSalary = async (id: string) => {
    await supabaseService.deleteSalary(id);
    setSalaries(prev => prev.filter(s => s.id !== id));
  };

  const addNewUser = async (u: StaffUser) => {
    const res = await supabaseService.insertUser(u);
    if (res) setUsers(prev => [...prev, u]);
    return { success: !!res };
  };
  const removeUser = async (id: string) => {
    await supabaseService.deleteUser(id);
    setUsers(prev => prev.filter(u => u.id !== id));
  };
  const updateUserProfile = async (id: string, data: Partial<StaffUser>) => {
    const res = await supabaseService.updateUser(id, data);
    if (res) setUsers(prev => prev.map(u => u.id === id ? { ...u, ...data } : u));
    return res;
  };

  return (
    <DataContext.Provider value={{
      patients, inventory, clinicalServices, appointments, invoices, expenses, salaries, users, patientHistory, daftraStatus,
      refreshData, addNewPatient, updatePat, deletePat, addNewHistory, addNewMedicine, updateMed, deleteMed, 
      addService, removeService, addTransaction, addNewAppointment, addExpense, removeExpense, addSalary, removeSalary,
      addNewUser, removeUser, updateUserProfile, isLoading
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { ShoppingBag, Trash2, Package, DollarSign, Wallet, Stethoscope, Store, RotateCcw, Plus, Search } from 'lucide-react';
import { CartItem, ClinicalService, Product, Invoice } from '../types';
import { InvoiceReceipt } from '../components/InvoiceReceipt';
import { Invoice as InvoiceComponent } from '../components/Invoice';
import { useData } from '../context/DataContext';

interface Props {
  currency: string;
  t: (key: string) => string;
  mode?: 'pos' | 'services';
}

const POSView: React.FC<Props> = ({ currency, t, mode = 'pos' }) => {
  const { inventory, clinicalServices, addTransaction, addService } = useData();

  const [activeTab, setActiveTab] = useState<'inventory' | 'services'>(mode === 'services' ? 'services' : 'inventory');
  const [searchTerm, setSearchTerm] = useState('');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [discount, setDiscount] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'percent' | 'flat'>('percent');
  const [showReceipt, setShowReceipt] = useState(false);
  const [lastTransaction, setLastTransaction] = useState<any>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRefundMode, setIsRefundMode] = useState(false); 

  useEffect(() => {
    setActiveTab(mode === 'services' ? 'services' : 'inventory');
  }, [mode]);

  const addToCart = (item: Product | ClinicalService) => {
    const isService = activeTab === 'services';
    const product = item as Product;

    if (!isService && !isRefundMode && product.stock !== undefined && product.stock <= 0) {
      alert("Xog: Alaabtan ma jirto (Out of stock)");
      return;
    }

    const existing = cart.find(i => i.id === item.id);
    if (existing) {
      if (!isService && !isRefundMode && product.stock !== undefined && existing.quantity >= product.stock) return;
      setCart(cart.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i));
    } else {
      setCart([...cart, { 
        id: item.id, 
        name: item.name, 
        price: item.price, 
        stock: (item as Product).stock ?? 9999, 
        category: (item as Product).category || 'Service', 
        expiryDate: (item as Product).expiryDate || '',
        quantity: 1 
      }]);
    }
  };

  const calculateSubtotal = () => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const calculateTotal = () => {
    const sub = calculateSubtotal();
    return discountType === 'percent' ? sub * (1 - discount / 100) : Math.max(0, sub - discount);
  };

  const handleCheckout = async (method: string) => {
    if (isProcessing || cart.length === 0) return;
    setIsProcessing(true);

    const finalTotal = calculateTotal();
    const transactionId = `INV-${Date.now().toString().slice(-6)}`;
    const finalAmount = isRefundMode ? -Math.abs(finalTotal) : finalTotal;

    const inv: Invoice = { 
      id: transactionId, 
      patientName: mode === 'services' ? 'Clinical Walk-in' : 'Pharmacy Client', 
      date: new Date().toISOString().split('T')[0], 
      amount: finalAmount, 
      discount: discount, 
      totalPaid: finalAmount, 
      status: isRefundMode ? 'Refunded' : 'Paid', 
      type: mode === 'services' ? 'Dental' : 'Pharmacy', 
      method: method,
      isRefund: isRefundMode 
    };

    const itemsToDeduct = cart.map(c => ({
      id: c.id,
      quantity: isRefundMode ? -c.quantity : c.quantity,
      currentStock: inventory.find(i => i.id === c.id)?.stock || 0
    }));

    try {
      const success = await addTransaction(inv, activeTab === 'inventory' ? itemsToDeduct : []);
      if (success) {
          setLastTransaction({ ...inv, items: [...cart], transactionId, total: finalAmount });
          setShowReceipt(true);
          setCart([]); 
          setDiscount(0);
          setIsRefundMode(false);
      }
    } catch (e) {
      alert("Cillad ayaa dhacday!");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className={`h-full flex flex-col lg:flex-row bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden relative transition-all ${isRefundMode ? 'border-rose-400 bg-rose-50/10' : ''}`}>
      {showReceipt && lastTransaction && mode === 'pos' && <InvoiceReceipt {...lastTransaction} onClose={() => setShowReceipt(false)} />}
      {showReceipt && lastTransaction && mode === 'services' && <InvoiceComponent {...lastTransaction} onClose={() => setShowReceipt(false)} t={t} />}

      <div className="flex-1 flex flex-col min-w-0 bg-slate-50/50">
        <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-white backdrop-blur-xl bg-white/90">
           <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white shadow-xl ${isRefundMode ? 'bg-rose-600' : (mode === 'services' ? 'bg-emerald-600' : 'bg-blue-600')}`}>
                 {isRefundMode ? <RotateCcw className="w-6 h-6" /> : (mode === 'services' ? <Stethoscope className="w-6 h-6" /> : <Store className="w-6 h-6" />)}
              </div>
              <div>
                <h2 className="text-2xl font-black text-slate-900 tracking-tight">{isRefundMode ? 'Refund Terminal' : (mode === 'services' ? 'Clinical Services' : 'Pharmacy POS')}</h2>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{isRefundMode ? 'Processing Return' : 'Ready for Transaction'}</p>
              </div>
           </div>
           <div className="flex items-center gap-4">
              <div className="relative w-64">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input 
                  type="text" 
                  placeholder="Search..." 
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold outline-none focus:bg-white focus:border-blue-500 transition-all"
                />
              </div>
              <button onClick={() => setIsRefundMode(!isRefundMode)} className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest border transition-all flex items-center gap-2 ${isRefundMode ? 'bg-rose-600 text-white' : 'bg-white text-rose-600 border-rose-200 hover:bg-rose-50'}`}>
                <RotateCcw className="w-4 h-4" /> Refund Mode
              </button>
           </div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 no-scrollbar">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6">
            {(activeTab === 'services' ? clinicalServices : inventory)
              .filter(i => i.name.toLowerCase().includes(searchTerm.toLowerCase()))
              .map(item => (
                <div key={item.id} onClick={() => addToCart(item)} className={`bg-white p-6 rounded-[2rem] border border-slate-100 cursor-pointer transition-all hover:shadow-2xl hover:border-blue-500 active:scale-95 group relative overflow-hidden ${(!isRefundMode && (item as Product).stock === 0) ? 'opacity-40 grayscale pointer-events-none' : ''}`}>
                   <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-4 transition-colors ${activeTab === 'services' ? 'bg-emerald-50 text-emerald-600 group-hover:bg-emerald-600 group-hover:text-white' : 'bg-blue-50 text-blue-600 group-hover:bg-blue-600 group-hover:text-white'}`}>
                      {activeTab === 'services' ? <Stethoscope className="w-6 h-6" /> : <Package className="w-6 h-6" />}
                   </div>
                   <h3 className="font-black text-slate-800 text-sm mb-1 leading-tight">{item.name}</h3>
                   <div className="flex justify-between items-end mt-4">
                      <span className="text-xl font-black text-slate-900">{currency}{item.price}</span>
                      {activeTab === 'inventory' && <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg ${(item as Product).stock < 10 ? 'bg-rose-50 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>Stock: {(item as Product).stock}</span>}
                   </div>
                </div>
            ))}
          </div>
        </div>
      </div>

      {/* Checkout Sidebar */}
      <div className="w-full lg:w-[450px] bg-white border-l border-slate-100 flex flex-col shadow-2xl z-10">
        <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
           <h3 className="text-sm font-black uppercase tracking-[0.2em] text-slate-900">Checkout Basket</h3>
           <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-white text-[10px] font-black shadow-lg ${isRefundMode ? 'bg-rose-600' : 'bg-blue-600'}`}>{cart.length}</div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-6 no-scrollbar">
          {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center opacity-30 text-center">
               <ShoppingBag className="w-32 h-32 mb-6 stroke-1" />
               <p className="font-black uppercase tracking-[0.2em] text-[10px]">Your basket is empty</p>
             </div>
          ) : (
            cart.map((item, idx) => (
              <div key={idx} className="flex items-center justify-between p-5 bg-slate-50 rounded-[1.5rem] border border-slate-100 group transition-all hover:bg-white hover:shadow-xl">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center font-black text-blue-600 border border-slate-200">x{item.quantity}</div>
                    <div>
                       <p className="font-black text-slate-900 text-sm truncate w-32">{item.name}</p>
                       <p className="text-[10px] font-bold text-blue-600">{currency}{item.price.toFixed(2)}</p>
                    </div>
                 </div>
                 <button onClick={() => setCart(cart.filter(c => c.id !== item.id))} className="p-3 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
              </div>
            ))
          )}
        </div>

        <div className={`p-10 border-t border-slate-200 space-y-8 ${isRefundMode ? 'bg-rose-50/30' : 'bg-slate-50/30'}`}>
          <div className="space-y-4">
             <div className="flex justify-between items-center text-slate-400 text-xs font-bold uppercase tracking-widest">
                <span>Subtotal</span>
                <span>{currency}{calculateSubtotal().toFixed(2)}</span>
             </div>
             {!isRefundMode && (
                <div className="flex justify-between items-center text-rose-500 text-xs font-bold uppercase tracking-widest">
                   <span>Discount ({discountType === 'percent' ? `${discount}%` : currency})</span>
                   <span>-{currency}{(calculateSubtotal() - calculateTotal()).toFixed(2)}</span>
                </div>
             )}
             <div className="pt-6 border-t border-slate-200 flex justify-between items-center">
                <span className="text-sm font-black uppercase tracking-[0.2em] text-slate-900">Grand Total</span>
                <span className={`text-4xl font-black ${isRefundMode ? 'text-rose-600' : 'text-blue-700'}`}>{isRefundMode ? '-' : ''}{currency}{calculateTotal().toFixed(2)}</span>
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <button onClick={() => handleCheckout('Cash')} disabled={cart.length === 0 || isProcessing} className="py-5 bg-white border-2 border-slate-200 rounded-3xl font-black text-[10px] uppercase tracking-widest hover:border-blue-600 hover:text-blue-600 transition-all shadow-sm flex flex-col items-center gap-2">
                <DollarSign className="w-5 h-5" /> Cash Payment
             </button>
             <button onClick={() => handleCheckout('EVC-Plus')} disabled={cart.length === 0 || isProcessing} className={`py-5 text-white rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-2xl transition-all flex flex-col items-center gap-2 ${isRefundMode ? 'bg-rose-600 hover:bg-rose-700' : 'bg-blue-600 hover:bg-blue-700'}`}>
                <Wallet className="w-5 h-5" /> Mobile Money
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default POSView;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabaseService } from '../services/supabaseService';
import { daftraApi } from '../services/daftraService';
import { 
  Patient, Medicine, Appointment, Invoice, Expense, Salary, 
  StaffUser, ClinicalService, PatientHistory 
} from '../types';

interface DataContextType {
  patients: Patient[];
  inventory: Medicine[];
  clinicalServices: ClinicalService[];
  appointments: Appointment[];
  invoices: Invoice[];
  expenses: Expense[];
  salaries: Salary[];
  users: StaffUser[];
  patientHistory: PatientHistory[];
  daftraStatus: 'checking' | 'connected' | 'error';
  refreshData: () => Promise<void>;

  // Daftra integration check
  checkDaftra: () => Promise<void>;

  // Patient Actions
  addNewPatient: (p: Patient) => Promise<void>;
  updatePat: (id: string, p: Partial<Patient>) => Promise<void>;
  deletePat: (id: string) => Promise<void>;

  // History
  addNewHistory: (h: PatientHistory) => Promise<void>;

  // Inventory
  addNewMedicine: (m: Medicine) => Promise<void>;
  updateMed: (id: string, m: Partial<Medicine>) => Promise<void>;
  deleteMed: (id: string) => Promise<void>;

  // Services
  addService: (s: ClinicalService) => Promise<void>;
  removeService: (id: string) => Promise<void>;

  // Sales
  addTransaction: (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => Promise<boolean>;

  // Appointments
  addNewAppointment: (a: Appointment) => Promise<void>;

  // Finance
  addExpense: (e: Expense) => Promise<void>;
  removeExpense: (id: string) => Promise<void>;
  addSalary: (s: Salary) => Promise<void>;
  removeSalary: (id: string) => Promise<void>;

  // User Management
  addNewUser: (u: StaffUser) => Promise<{success: boolean, error?: string}>;
  removeUser: (id: string) => Promise<void>;
  updateUserProfile: (id: string, data: Partial<StaffUser>) => Promise<StaffUser | null>;

  isLoading: boolean;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [inventory, setInventory] = useState<Medicine[]>([]);
  const [clinicalServices, setClinicalServices] = useState<ClinicalService[]>([]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [salaries, setSalaries] = useState<Salary[]>([]);
  const [users, setUsers] = useState<StaffUser[]>([]);
  const [patientHistory, setPatientHistory] = useState<PatientHistory[]>([]);
  const [daftraStatus, setDaftraStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [isLoading, setIsLoading] = useState(true);

  const refreshData = async () => {
    try {
      const [p, m, srv, a, i, e, s, u] = await Promise.all([
        supabaseService.getPatients(),
        supabaseService.getInventory(),
        supabaseService.getServices(),
        supabaseService.getAppointments(),
        supabaseService.getInvoices(),
        supabaseService.getExpenses(),
        supabaseService.getSalaries(),
        supabaseService.getUsers()
      ]);

      if (p) setPatients(p);
      if (m) setInventory(m);
      if (srv) setClinicalServices(srv);
      if (a) setAppointments(a);
      if (i) setInvoices(i);
      if (e) setExpenses(e);
      if (s) setSalaries(s);
      if (u) setUsers(u);

      const h = JSON.parse(localStorage.getItem('dhool_local_history') || '[]');
      setPatientHistory(h);
    } catch (error) {
      console.error("Context Refresh Error:", error);
    } finally {
      setIsLoading(false);
    }
  };

  // Fix: Added checkDaftra function to manage Daftra connection status
  const checkDaftra = async () => {
    setDaftraStatus('checking');
    const res = await daftraApi.checkConnection();
    setDaftraStatus(res ? 'connected' : 'error');
  };

  useEffect(() => {
    refreshData();
    checkDaftra();
  }, []);

  const addNewPatient = async (p: Patient) => {
    await supabaseService.insertPatient(p);
    setPatients(prev => [...prev, p]);
  };
  const updatePat = async (id: string, p: Partial<Patient>) => {
    await supabaseService.updatePatient(id, p);
    setPatients(prev => prev.map(item => item.id === id ? { ...item, ...p } : item));
  };
  const deletePat = async (id: string) => {
    await supabaseService.deletePatient(id);
    setPatients(prev => prev.filter(p => p.id !== id));
  };

  const addNewHistory = async (h: PatientHistory) => {
    await supabaseService.insertHistory(h);
    setPatientHistory(prev => [h, ...prev]);
    localStorage.setItem('dhool_local_history', JSON.stringify([h, ...patientHistory]));
  };

  const addNewMedicine = async (m: Medicine) => {
    await supabaseService.insertMedicine(m);
    setInventory(prev => [...prev, m]);
  };
  const updateMed = async (id: string, m: Partial<Medicine>) => {
    await supabaseService.updateMedicine(id, m);
    setInventory(prev => prev.map(item => item.id === id ? { ...item, ...m } : item));
  };
  const deleteMed = async (id: string) => {
    await supabaseService.deleteMedicine(id);
    setInventory(prev => prev.filter(m => m.id !== id));
  };

  const addService = async (s: ClinicalService) => {
    await supabaseService.insertService(s);
    setClinicalServices(prev => [...prev, s]);
  };
  const removeService = async (id: string) => {
    await supabaseService.deleteService(id);
    setClinicalServices(prev => prev.filter(s => s.id !== id));
  };

  const addTransaction = async (inv: Invoice, items?: {id:string, quantity:number, currentStock: number}[]) => {
    const success = await supabaseService.createTransaction(inv, items);
    if (success) {
      setInvoices(prev => [inv, ...prev]);
      if (items) {
        const itemMap = new Map(items.map(i => [i.id, i.quantity]));
        setInventory(prev => prev.map(prod => {
          const qty = itemMap.get(prod.id);
          if (qty) return { ...prod, stock: Math.max(0, prod.stock - qty) };
          return prod;
        }));
      }
    }
    return success;
  };

  const addNewAppointment = async (a: Appointment) => {
    await supabaseService.insertAppointment(a);
    setAppointments(prev => [a, ...prev]);
  };

  const addExpense = async (e: Expense) => {
    await supabaseService.insertExpense(e);
    setExpenses(prev => [e, ...prev]);
  };
  const removeExpense = async (id: string) => {
    await supabaseService.deleteExpense(id);
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const addSalary = async (s: Salary) => {
    await supabaseService.insertSalary(s);
    setSalaries(prev => [s, ...prev]);
  };
  const removeSalary = async (id: string) => {
    await supabaseService.deleteSalary(id);
    setSalaries(prev => prev.filter(s => s.id !== id));
  };

  const addNewUser = async (u: StaffUser) => {
    const res = await supabaseService.insertUser(u);
    if (res) setUsers(prev => [...prev, u]);
    return { success: !!res };
  };
  const removeUser = async (id: string) => {
    await supabaseService.deleteUser(id);
    setUsers(prev => prev.filter(u => u.id !== id));
  };
  const updateUserProfile = async (id: string, data: Partial<StaffUser>) => {
    const res = await supabaseService.updateUser(id, data);
    if (res) setUsers(prev => prev.map(u => u.id === id ? { ...u, ...data } : u));
    return res;
  };

  return (
    <DataContext.Provider value={{
      patients, inventory, clinicalServices, appointments, invoices, expenses, salaries, users, patientHistory, daftraStatus,
      refreshData, addNewPatient, updatePat, deletePat, addNewHistory, addNewMedicine, updateMed, deleteMed, 
      addService, removeService, addTransaction, addNewAppointment, addExpense, removeExpense, addSalary, removeSalary,
      addNewUser, removeUser, updateUserProfile, isLoading, checkDaftra
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error('useData must be used within DataProvider');
  return context;
};

