                    <div className="space-y-6">
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                         <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
                            <p className="text-gray-400 text-xs font-bold uppercase mb-1">Total Outstanding</p>
                            <h3 className="text-2xl font-black text-red-600">${getPatientBalance(selectedPatient.id).toFixed(2)}</h3>
                         </div>
                         <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
                            <p className="text-gray-400 text-xs font-bold uppercase mb-1">Total Spent</p>
                            <h3 className="text-2xl font-black text-blue-800">${invoices.filter(tx => tx.patientName === selectedPatient.name).reduce((sum, tx) => sum + (tx.amount), 0).toFixed(2)}</h3>
                         </div>
                       </div>

                       <h3 className="font-bold text-gray-800">Payment History</h3>
                       <div className="space-y-3">
                         {invoices.filter(tx => tx.patientName === selectedPatient.name).length === 0 ? (
                           <p className="text-gray-400 text-center py-4">No billing history found.</p>
                         ) : (
                           invoices.filter(tx => tx.patientName === selectedPatient.name).map(tx => (
                             <div key={tx.id} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex justify-between items-center">
                               <div>
                                 <p className="text-xs text-gray-400 mb-1">{tx.date}</p>
                                 <div className="flex items-center gap-2">
                                    <span className="font-bold text-gray-800">Total: ${ tx.amount.toFixed(2)}</span>
                                    <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${ tx.status === 'Pending' ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                                      { tx.status }
                                    </span>
                                 </div>
                               </div>
                               <div className="text-right">
                                  <p className="text-xs font-medium text-gray-500">Method: {tx.method}</p>
                                  <p className={`text-xs font-bold ${tx.status === 'Paid' ? 'text-green-600' : 'text-amber-600'}`}>Paid: ${tx.status === 'Paid' ? tx.amount.toFixed(2) : '0.00'}</p>
                               </div>
                             </div>
                           ))
                         )}
                       </div>
                    </div>
                 )}
              </div>
           </div>
         </div>
      )}
    </div>
  );
};

