// Helper to handle Firestore requests with Local Storage Fallback
const handleRequest = async <T>(
  operation: () => Promise<T>,
  localKey: string,
  action: 'get' | 'insert' | 'update' | 'delete',
  payload?: any
): Promise<T | any> => {
  try {
    const data = await operation();
    if (action === 'get' && data) {
       localStorage.setItem(localKey, JSON.stringify(data));
    }
    return data;
  } catch (error) {
    console.warn(`Firebase ${action} failed for ${localKey}. Using Local Storage.`, error);
    let localData = JSON.parse(localStorage.getItem(localKey) || '[]');

    if (action === 'get') return localData;

    if (action === 'insert') {
      const newItem = Array.isArray(payload) ? payload[0] : payload;
      // Ensure ID exists for local fallback
      if (!newItem.id) newItem.id = Date.now().toString();
      const updatedList = [newItem, ...localData];
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return newItem;
    }

    if (action === 'update') {
      const updatedList = localData.map((item: any) => item.id === payload.id ? { ...item, ...payload.updates } : item);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return payload.updates;
    }

    if (action === 'delete') {
      const updatedList = localData.filter((item: any) => item.id !== payload);
      localStorage.setItem(localKey, JSON.stringify(updatedList));
      return null;
    }
  }
};

export const firebaseService = {
  // Auth
  login: async (email: string, password?: string) => {
    try {
      // First try Firebase Auth
      if (password) {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        // Get extra user details from Firestore 'users' collection
        const userDoc = await getDoc(doc(db, "users", userCredential.user.uid));
        if (userDoc.exists()) {
            return { ...userDoc.data(), id: userCredential.user.uid } as StaffUser;
        }
        // Fallback if just created in Auth but not in DB
        return { 
            id: userCredential.user.uid, 
            email: userCredential.user.email, 
            name: userCredential.user.email?.split('@')[0] || 'User',
            role: 'Staff', 
            status: 'Active' 
        } as StaffUser;
      }
      throw new Error("Password required for Firebase Auth");
    } catch (e) {
      console.warn("Firebase Auth Failed, checking local users for demo/offline mode", e);
      const localUsers: StaffUser[] = JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
      const localUser = localUsers.find(u => u.email === email);
      if (localUser && localUser.password === password) return localUser;
      return null;
    }
  },

  logout: async () => {
    await signOut(auth);
  },

  // Users CRUD
  getUsers: async () => handleRequest(async () => {
    const q = query(collection(db, "users"), orderBy("name"));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ ...d.data(), id: d.id })) as StaffUser[];
  }, KEYS.USERS, 'get'),

  insertUser: async (user: StaffUser) => handleRequest(async () => {
    // For users, we typically use the Auth UID as doc ID, but here we use generated ID
    await setDoc(doc(db, "users", user.id), user);
    return user;
  }, KEYS.USERS, 'insert', user),

  updateUser: async (id: string, updates: Partial<StaffUser>) => handleRequest(async () => {
    await updateDoc(doc(db, "users", id), updates);
    return updates;
  }, KEYS.USERS, 'update', { id, updates }),

  deleteUser: async (id: string) => handleRequest(async () => {
    await deleteDoc(doc(db, "users", id));
  }, KEYS.USERS, 'delete', id),

  // Patients CRUD
  getPatients: async () => handleRequest(async () => {
    const q = query(collection(db, "patients"), orderBy("name"));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ ...d.data(), id: d.id })) as Patient[];
  }, KEYS.PATIENTS, 'get'),

  insertPatient: async (patient: Patient) => handleRequest(async () => {
    await setDoc(doc(db, "patients", patient.id), patient);
    return patient;
