    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({ ...d.data(), id: d.id })) as ClinicalService[];
  }, KEYS.SERVICES, 'get'),

  insertService: async (service: ClinicalService) => handleRequest(async () => {
